var areaOfMaxDiagonal = function(dimensions) {
    let bestD2 = -1, bestArea = 0;
    for (const [l, w] of dimensions) {
        const d2 = l * l + w * w;
        const area = l * w;
        if (d2 > bestD2 || (d2 === bestD2 && area > bestArea)) {
            bestD2 = d2;
            bestArea = area;
        }
    }
    return bestArea;
};
